const output = $input.first().json.output || '';
const chatId = $('Telegram Trigger').first().json.message.chat.id;
const chunkSize = 4000;
const chunks = [];
for (let i = 0; i < output.length; i += chunkSize) {
  chunks.push({
    json: {
      text: output.substring(i, i + chunkSize),
      chatId: chatId
    }
  });
}
return chunks;
